//! Lifepath roller — WP-504.
//!
//! Wires the authored RON tables from `content/tables/lifepath/` (loaded by
//! WP-214's [`crate::catalog::lifepath`] loaders) together with the
//! deterministic [`crate::Rng`] to produce a complete, randomised
//! [`Lifepath`] record for a given [`Role`].
//!
//! # Roll procedure
//!
//! All shared tables (pp.43–53) are rolled first; then the role-specific
//! lifepath file (pp.54–69) is loaded and rolled. Relationship beacons
//! (friends, enemies, tragic loves) each get at least one entry generated by
//! rolling d10 on the appropriate table (pp.51–52). Names default to
//! flavour-text placeholders ("Friend 1", "Enemy 1", "Lover 1") per the
//! WP-504 spec since the rulebook does not print a canonical name list for
//! these NPCs.
//!
//! # Determinism
//!
//! Every dice call goes through the caller-supplied `rng: &mut Rng`. The same
//! seed always produces the same [`Lifepath`]. See [`crate::rng`].
//!
//! # Rulebook references
//!
//! See pp.43–69 ("Tales from The Street").

use crate::catalog::lifepath::{
    load_affectations_table, load_clothing_table, load_cultural_origin_table, load_enemies_table,
    load_family_background_table, load_family_crisis_table, load_friends_table,
    load_hairstyle_table, load_life_goals_table, load_motivations_table, load_personality_table,
    load_role_lifepath, load_tragic_loves_table, BeaconKind, ExecLifepath, FamilyBackground,
    FixerLifepath, LawmanLifepath, Lifepath, MediaLifepath, MedtechLifepath, NetrunnerLifepath,
    NomadLifepath, RelationshipBeacon, RockerboyLifepath, RoleLifepath, RoleLifepathTables,
    SoloLifepath, TechLifepath,
};
use crate::character::data::Role;
use crate::dice::{d10, d6};
use crate::error::RulesError;
use crate::rng::Rng;
use std::path::Path;

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/// Roll a complete Lifepath for the given role using the authored RON tables.
///
/// Loads every shared lifepath table from `tables_dir` (e.g.
/// `content/tables/lifepath/`), rolls on each using `rng`, then loads and
/// rolls the role-specific lifepath file. Returns a fully populated
/// [`Lifepath`] struct.
///
/// Friends, enemies, and tragic loves each produce **at least one** beacon.
/// Additional beacons are added for each positive result of `d10 - 7`
/// (minimum 0), matching the pp.51–52 book mechanic.
///
/// # Errors
///
/// Returns [`RulesError::CatalogLoadFailed`] if any RON file cannot be read
/// or parsed. Returns [`RulesError::InvalidLifepathRoll`] if a table lookup
/// returns `None` — this indicates a corrupt content file or a test-fixture
/// bug.
///
/// # See pp.43–69
pub fn roll_lifepath(role: Role, tables_dir: &Path, rng: &mut Rng) -> Result<Lifepath, RulesError> {
    // --- Shared tables (pp.43–53) ------------------------------------------

    // Cultural origin (p.45) — d10.
    let cultural_origin_table =
        load_cultural_origin_table(&tables_dir.join("cultural_origin.ron"))?;
    let co_roll = d10(rng);
    let co_row =
        cultural_origin_table
            .lookup(co_roll)
            .ok_or_else(|| RulesError::InvalidLifepathRoll {
                table: "cultural_origin".into(),
                roll: co_roll,
            })?;
    let cultural_region = co_row.region.clone();
    // Pick the first language from the list as a deterministic default.
    // See pp.43-69: the book says "pick one"; we default to the first entry
    // for the deterministic roller — a higher-level selection UI can override.
    let language_spoken = co_row.languages.first().cloned().unwrap_or_default();

    // Personality (p.46) — d10.
    let personality_table = load_personality_table(&tables_dir.join("personality.ron"))?;
    let p_roll = d10(rng);
    let personality = personality_table
        .lookup(p_roll)
        .ok_or_else(|| RulesError::InvalidLifepathRoll {
            table: "personality".into(),
            roll: p_roll,
        })?
        .clone();

    // Clothing style (p.47) — d10.
    let clothing_table = load_clothing_table(&tables_dir.join("clothing.ron"))?;
    let cl_roll = d10(rng);
    let clothing_style = clothing_table
        .lookup(cl_roll)
        .ok_or_else(|| RulesError::InvalidLifepathRoll {
            table: "clothing".into(),
            roll: cl_roll,
        })?
        .clone();

    // Hairstyle (p.47) — d10.
    let hairstyle_table = load_hairstyle_table(&tables_dir.join("hairstyle.ron"))?;
    let hs_roll = d10(rng);
    let hairstyle = hairstyle_table
        .lookup(hs_roll)
        .ok_or_else(|| RulesError::InvalidLifepathRoll {
            table: "hairstyle".into(),
            roll: hs_roll,
        })?
        .clone();

    // Affectations (p.47) — d10.
    let affectations_table = load_affectations_table(&tables_dir.join("affectations.ron"))?;
    let aff_roll = d10(rng);
    let affectations = affectations_table
        .lookup(aff_roll)
        .ok_or_else(|| RulesError::InvalidLifepathRoll {
            table: "affectations".into(),
            roll: aff_roll,
        })?
        .clone();

    // Motivations / What Do You Value Most? (p.48) — d10.
    let motivations_table = load_motivations_table(&tables_dir.join("motivations.ron"))?;
    let mot_roll = d10(rng);
    let motivation = motivations_table
        .lookup(mot_roll)
        .ok_or_else(|| RulesError::InvalidLifepathRoll {
            table: "motivations".into(),
            roll: mot_roll,
        })?
        .clone();

    // Family background (p.49) — d10.
    let family_bg_table = load_family_background_table(&tables_dir.join("family_background.ron"))?;
    let fb_roll = d10(rng);
    let fb_row =
        family_bg_table
            .lookup(fb_roll)
            .ok_or_else(|| RulesError::InvalidLifepathRoll {
                table: "family_background".into(),
                roll: fb_roll,
            })?;
    // childhood_environment, feelings_about_people, most_valued_person, and
    // most_valued_possession (pp.48, 50) are in sub-sections of pp.48-50 that
    // are not yet represented as separate RON tables in WP-214's content.
    // Per the WP-504 spec these are left blank; future content PRs can add them.
    let family_background = FamilyBackground {
        original_background: fb_row.label.clone(),
        description: fb_row.description.clone(),
        childhood_environment: String::new(),
        feelings_about_people: String::new(),
        most_valued_person: String::new(),
        most_valued_possession: String::new(),
    };

    // Family crisis (p.50) — d10.
    let family_crisis_table = load_family_crisis_table(&tables_dir.join("family_crisis.ron"))?;
    let fc_roll = d10(rng);
    let family_crisis = family_crisis_table
        .lookup(fc_roll)
        .ok_or_else(|| RulesError::InvalidLifepathRoll {
            table: "family_crisis".into(),
            roll: fc_roll,
        })?
        .clone();

    // Life goals (p.53) — d10.
    let life_goals_table = load_life_goals_table(&tables_dir.join("life_goals.ron"))?;
    let lg_roll = d10(rng);
    let life_goal = life_goals_table
        .lookup(lg_roll)
        .ok_or_else(|| RulesError::InvalidLifepathRoll {
            table: "life_goals".into(),
            roll: lg_roll,
        })?
        .clone();

    // Friends (p.51) — at least 1 + (d10 - 7, min 0) more.
    let friends_table = load_friends_table(&tables_dir.join("friends.ron"))?;
    let friends = roll_beacons(&friends_table, BeaconKind::Friend, "Friend", rng)?;

    // Enemies (p.51) — at least 1 + (d10 - 7, min 0) more.
    let enemies_table = load_enemies_table(&tables_dir.join("enemies.ron"))?;
    let enemies = roll_beacons(&enemies_table, BeaconKind::Enemy, "Enemy", rng)?;

    // Tragic loves (p.52) — at least 1 + (d10 - 7, min 0) more.
    let tragic_loves_table = load_tragic_loves_table(&tables_dir.join("tragic_loves.ron"))?;
    let tragic_loves = roll_beacons(&tragic_loves_table, BeaconKind::Lover, "Lover", rng)?;

    // --- Role-specific lifepath (pp.54–69) ----------------------------------

    let role_specific = roll_role_lifepath(role, tables_dir, rng)?;

    Ok(Lifepath {
        cultural_region,
        language_spoken,
        personality,
        clothing_style,
        hairstyle,
        affectations,
        motivation,
        life_goal,
        family_background,
        family_crisis,
        friends,
        enemies,
        tragic_loves,
        role_specific,
    })
}

