// Internal helpers
// ---------------------------------------------------------------------------

/// Roll one or more relationship beacons from a table.
///
/// Always produces at least one beacon. Additional beacons are added for
/// each positive result of `d10 - 7` (minimum 0), matching the pp.51–52
/// book mechanic. Names are placeholder strings ("Friend 1", "Enemy 1", …)
/// since the rulebook does not list canonical NPC names in these tables.
/// The LLM narrator layer or a player-facing UI assigns real names.
///
/// See pp.51–52.
fn roll_beacons(
    table: &crate::catalog::lifepath::LifepathTable<String>,
    kind: BeaconKind,
    label: &str,
    rng: &mut Rng,
) -> Result<Vec<RelationshipBeacon>, RulesError> {
    // Total count = 1 mandatory + max(d10 - 7, 0).
    let extra_roll = d10(rng);
    let extra = if extra_roll > 7 {
        (extra_roll - 7) as usize
    } else {
        0
    };
    let count = 1 + extra;

    let mut beacons = Vec::with_capacity(count);
    for i in 1..=count {
        let roll = d10(rng);
        let note = table
            .lookup(roll)
            .ok_or_else(|| RulesError::InvalidLifepathRoll {
                table: label.to_lowercase(),
                roll,
            })?
            .clone();
        beacons.push(RelationshipBeacon {
            // Placeholder name — see WP-504 spec: "use 'Friend 1', 'Friend 2'
            // placeholders". See pp.59+.
            name: format!("{label} {i}"),
            kind,
            note,
        });
    }
    Ok(beacons)
}

/// Roll a single sub-table from a [`RoleLifepathTables`] set.
///
/// Uses `roll_fn` to generate a roll value, then looks it up in the named
/// sub-table. Returns [`RulesError::CatalogLoadFailed`] if the sub-table is
/// absent and [`RulesError::InvalidLifepathRoll`] if the roll is out of range.
///
/// See pp.54–69.
fn roll_sub_table(
    role_tables: &RoleLifepathTables,
    table_name: &str,
    roll_fn: fn(&mut Rng) -> u8,
    rng: &mut Rng,
) -> Result<String, RulesError> {
    let table = role_tables
        .get(table_name)
        .ok_or_else(|| RulesError::CatalogLoadFailed {
            path: std::path::PathBuf::from(format!("<role_lifepath>/{table_name}")),
            source: format!("sub-table '{table_name}' not found in role file"),
        })?;
    let roll = roll_fn(rng);
    table
        .lookup(roll)
        .ok_or_else(|| RulesError::InvalidLifepathRoll {
            table: table_name.to_string(),
            roll,
        })
        .cloned()
}

/// Load and roll all role-specific sub-tables for the given role.
///
/// Dispatches to the per-role helper based on `role`. Each helper loads the
/// correct RON file from `tables_dir` and rolls every sub-table.
///
/// See pp.54–69.
fn roll_role_lifepath(
    role: Role,
    tables_dir: &Path,
    rng: &mut Rng,
) -> Result<RoleLifepath, RulesError> {
    let role_filename = match role {
        Role::Rockerboy => "rockerboy.ron",
        Role::Solo => "solo.ron",
        Role::Netrunner => "netrunner.ron",
        Role::Tech => "tech.ron",
        Role::Medtech => "medtech.ron",
        Role::Media => "media.ron",
        Role::Lawman => "lawman.ron",
        Role::Exec => "exec.ron",
        Role::Fixer => "fixer.ron",
        Role::Nomad => "nomad.ron",
    };
    let role_tables = load_role_lifepath(&tables_dir.join(role_filename))?;

    match role {
        Role::Rockerboy => roll_rockerboy(&role_tables, rng),
        Role::Solo => roll_solo(&role_tables, rng),
        Role::Netrunner => roll_netrunner(&role_tables, rng),
        Role::Tech => roll_tech(&role_tables, rng),
        Role::Medtech => roll_medtech(&role_tables, rng),
        Role::Media => roll_media(&role_tables, rng),
        Role::Lawman => roll_lawman(&role_tables, rng),
        Role::Exec => roll_exec(&role_tables, rng),
        Role::Fixer => roll_fixer(&role_tables, rng),
        Role::Nomad => roll_nomad(&role_tables, rng),
    }
}

/// Roll the Rockerboy lifepath (p.54).
///
/// "Are You in a Group or a Solo Act?" and "Were You Once in a Group?" are
/// choose-only on p.54 — no roll table. `group_or_solo` defaults to "Solo
/// Act" and `were_in_group` to blank ("no") for the roller; a player-facing
/// UI should let the player choose. `why_left` is rolled regardless (only
/// meaningful when `were_in_group` is set). See pp.43-69.
fn roll_rockerboy(
    role_tables: &RoleLifepathTables,
    rng: &mut Rng,
) -> Result<RoleLifepath, RulesError> {
    let rockerboy_type = roll_sub_table(role_tables, "rockerboy_type", d10, rng)?;
    let venue = roll_sub_table(role_tables, "venue", d6, rng)?;
    let whos_gunning = roll_sub_table(role_tables, "whos_gunning", d6, rng)?;
    let why_left = roll_sub_table(role_tables, "why_left", d6, rng)?;

    Ok(RoleLifepath::Rockerboy(RockerboyLifepath {
        rockerboy_type,
        group_or_solo: "Solo Act".to_string(),
        were_in_group: String::new(),
        why_left,
        venue,
        whos_gunning,
    }))
}

/// Roll the Solo lifepath (p.55).
fn roll_solo(role_tables: &RoleLifepathTables, rng: &mut Rng) -> Result<RoleLifepath, RulesError> {
    let solo_type = roll_sub_table(role_tables, "solo_type", d6, rng)?;
    let moral_compass = roll_sub_table(role_tables, "moral_compass", d6, rng)?;
    let whos_gunning = roll_sub_table(role_tables, "whos_gunning", d6, rng)?;
    let operational_territory = roll_sub_table(role_tables, "operational_territory", d6, rng)?;

    Ok(RoleLifepath::Solo(SoloLifepath {
        solo_type,
        moral_compass,
        whos_gunning,
        operational_territory,
    }))
}

