/// Roll the Nomad lifepath (pp.68–69).
///
/// "Is Your Pack Based on Land, Air, or Sea?" is choose-only on p.68.
/// Defaults to "Land" — rolling the 1d10 `nomad_land` sub-table.
/// A player-facing UI should let the player choose; air/sea paths would roll
/// `nomad_air` / `nomad_sea` (1d6) instead. See pp.43-69.
fn roll_nomad(role_tables: &RoleLifepathTables, rng: &mut Rng) -> Result<RoleLifepath, RulesError> {
    let pack_size = roll_sub_table(role_tables, "pack_size", d6, rng)?;
    // Default to Land — rolls the 1d10 nomad_land sub-table. See p.68.
    let pack_business = roll_sub_table(role_tables, "nomad_land", d10, rng)?;
    let personal_role = roll_sub_table(role_tables, "personal_role", d6, rng)?;
    let philosophy = roll_sub_table(role_tables, "philosophy", d6, rng)?;
    let whos_gunning = roll_sub_table(role_tables, "whos_gunning", d6, rng)?;

    Ok(RoleLifepath::Nomad(NomadLifepath {
        pack_size,
        land_air_sea: "Land".to_string(),
        pack_business,
        personal_role,
        philosophy,
        whos_gunning,
    }))
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;
    use rand::SeedableRng;
    use std::path::PathBuf;

    /// Workspace-root-relative path to the lifepath content directory.
    fn lifepath_dir() -> PathBuf {
        let mut p = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
        p.pop(); // crates/rules -> crates
        p.pop(); // crates -> repo root
        p.push("content");
        p.push("tables");
        p.push("lifepath");
        p
    }

    /// Acceptance test: every required field is populated after a roll.
    ///
    /// See WP-504 acceptance tests.
    #[test]
    fn test_lifepath_complete() {
        let mut rng = Rng::seed_from_u64(42);
        let lp = roll_lifepath(Role::Solo, &lifepath_dir(), &mut rng)
            .expect("roll_lifepath must succeed for Solo");

        assert!(
            !lp.cultural_region.is_empty(),
            "cultural_region must be populated"
        );
        assert!(
            !lp.language_spoken.is_empty(),
            "language_spoken must be populated"
        );
        assert!(!lp.personality.is_empty(), "personality must be populated");
        assert!(
            !lp.clothing_style.is_empty(),
            "clothing_style must be populated"
        );
        assert!(!lp.hairstyle.is_empty(), "hairstyle must be populated");
        assert!(
            !lp.affectations.is_empty(),
            "affectations must be populated"
        );
        assert!(!lp.motivation.is_empty(), "motivation must be populated");
        assert!(!lp.life_goal.is_empty(), "life_goal must be populated");
        assert!(
            !lp.family_background.original_background.is_empty(),
            "family_background.original_background must be populated"
        );
        assert!(
            !lp.family_crisis.is_empty(),
            "family_crisis must be populated"
        );
        assert!(
            !lp.friends.is_empty(),
            "friends must have at least one entry"
        );
        assert!(
            !lp.enemies.is_empty(),
            "enemies must have at least one entry"
        );
        assert!(
            !lp.tragic_loves.is_empty(),
            "tragic_loves must have at least one entry"
        );
        assert!(
            matches!(lp.role_specific, RoleLifepath::Solo(_)),
            "role_specific must be Solo for a Solo roll"
        );
        if let RoleLifepath::Solo(ref s) = lp.role_specific {
            assert!(!s.solo_type.is_empty(), "solo_type must be populated");
            assert!(
                !s.moral_compass.is_empty(),
                "moral_compass must be populated"
            );
            assert!(!s.whos_gunning.is_empty(), "whos_gunning must be populated");
            assert!(
                !s.operational_territory.is_empty(),
                "operational_territory must be populated"
            );
        }
    }

    /// Acceptance test: a Solo roll produces the Solo lifepath table, not the
    /// Rockerboy's. See WP-504 acceptance tests.
    #[test]
    fn test_lifepath_role_specific_matches_role() {
        let mut rng_solo = Rng::seed_from_u64(1);
        let lp_solo = roll_lifepath(Role::Solo, &lifepath_dir(), &mut rng_solo)
            .expect("Solo roll must succeed");
        assert!(
            matches!(lp_solo.role_specific, RoleLifepath::Solo(_)),
            "Solo role must produce RoleLifepath::Solo"
        );

        let mut rng_rock = Rng::seed_from_u64(2);
        let lp_rock = roll_lifepath(Role::Rockerboy, &lifepath_dir(), &mut rng_rock)
            .expect("Rockerboy roll must succeed");
        assert!(
            matches!(lp_rock.role_specific, RoleLifepath::Rockerboy(_)),
            "Rockerboy role must produce RoleLifepath::Rockerboy"
        );
    }

    /// Acceptance test: at least one friend, one enemy, and one tragic love
    /// each have names. See WP-504 acceptance tests.
    #[test]
    fn test_friends_enemies_have_names() {
        let mut rng = Rng::seed_from_u64(99);
        let lp = roll_lifepath(Role::Netrunner, &lifepath_dir(), &mut rng)
            .expect("roll_lifepath must succeed for Netrunner");

        let first_friend = lp.friends.first().expect("must have at least one friend");
        assert!(
            !first_friend.name.is_empty(),
            "first friend must have a name"
        );

        let first_enemy = lp.enemies.first().expect("must have at least one enemy");
        assert!(!first_enemy.name.is_empty(), "first enemy must have a name");

        let first_lover = lp
            .tragic_loves
            .first()
            .expect("must have at least one tragic love");
        assert!(
            !first_lover.name.is_empty(),
            "first tragic lover must have a name"
        );
    }

    /// Acceptance test: same seed produces the same Lifepath (determinism).
    /// See WP-504 acceptance tests.
    #[test]
    fn test_lifepath_deterministic_with_seed() {
        let seed = 7777;
        let dir = lifepath_dir();

        let mut rng_a = Rng::seed_from_u64(seed);
        let lp_a = roll_lifepath(Role::Tech, &dir, &mut rng_a).expect("first roll must succeed");

        let mut rng_b = Rng::seed_from_u64(seed);
        let lp_b = roll_lifepath(Role::Tech, &dir, &mut rng_b).expect("second roll must succeed");

        assert_eq!(lp_a, lp_b, "same seed must produce identical Lifepath");
    }

    /// Sanity: all ten roles can be rolled without errors.
    #[test]
    fn test_all_roles_roll_successfully() {
        let dir = lifepath_dir();
        let roles = [
            Role::Rockerboy,
            Role::Solo,
            Role::Netrunner,
            Role::Tech,
            Role::Medtech,
            Role::Media,
            Role::Lawman,
            Role::Exec,
            Role::Fixer,
            Role::Nomad,
        ];
        for (seed, role) in roles.iter().enumerate() {
            let mut rng = Rng::seed_from_u64(seed as u64);
            roll_lifepath(*role, &dir, &mut rng)
                .unwrap_or_else(|e| panic!("roll_lifepath failed for {:?}: {e}", role));
        }
    }

    /// Sanity: friend, enemy, and tragic-love notes are non-empty and beacon
    /// kinds are correct.
    #[test]
    fn test_relationship_beacons_have_notes() {
        let mut rng = Rng::seed_from_u64(12345);
        let lp = roll_lifepath(Role::Exec, &lifepath_dir(), &mut rng).expect("roll must succeed");

        for f in &lp.friends {
            assert!(!f.note.is_empty(), "friend note must be non-empty");
            assert_eq!(f.kind, BeaconKind::Friend);
        }
        for e in &lp.enemies {
            assert!(!e.note.is_empty(), "enemy note must be non-empty");
            assert_eq!(e.kind, BeaconKind::Enemy);
        }
        for l in &lp.tragic_loves {
            assert!(!l.note.is_empty(), "tragic love note must be non-empty");
            assert_eq!(l.kind, BeaconKind::Lover);
        }
    }
}
